const r = $input.first().json;
const d = $('🔧 Build Close Payload').first().json;
const success = !r.Error && (r.Success === 1 || r.TicketID != null);
return [{
  json: {
    success,
    ticket_id: d.ticket_id,
    closed_at: d.closed_at,
    error: r.Error ? `${r.Error.ErrorCode}: ${r.Error.ErrorMessage}` : null
  }
}];
